(window.webpackJsonp=window.webpackJsonp||[]).push([[575],{562:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number[]}</span> <span class=\\"hljs-variable\\">piles</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> stoneGameII = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">piles</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> N=piles.length\\n  <span class=\\"hljs-keyword\\">let</span> rest=<span class=\\"hljs-built_in\\">Array</span>(N).fill(<span class=\\"hljs-number\\">0</span>)\\n  <span class=\\"hljs-keyword\\">let</span> hash={}\\n  rest[N<span class=\\"hljs-number\\">-1</span>]=piles[N<span class=\\"hljs-number\\">-1</span>]\\n  <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=N<span class=\\"hljs-number\\">-2</span>;i&gt;=<span class=\\"hljs-number\\">0</span>;i--){\\n    rest[i]=rest[i+<span class=\\"hljs-number\\">1</span>]+piles[i]\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> helper(<span class=\\"hljs-number\\">0</span>,<span class=\\"hljs-number\\">1</span>)\\n  \\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">helper</span>(<span class=\\"hljs-params\\">start,M</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(start&gt;=N)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">if</span>(<span class=\\"hljs-number\\">2</span>*M&gt;=N-start)<span class=\\"hljs-keyword\\">return</span> rest[start]\\n    <span class=\\"hljs-keyword\\">if</span>(hash[start+<span class=\\"hljs-string\\">\' \'</span>+M])<span class=\\"hljs-keyword\\">return</span> hash[start+<span class=\\"hljs-string\\">\' \'</span>+M]\\n    <span class=\\"hljs-keyword\\">let</span> min=<span class=\\"hljs-literal\\">Infinity</span>\\n    <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">1</span>;i&lt;=<span class=\\"hljs-number\\">2</span>*M;i++){\\n      min=<span class=\\"hljs-built_in\\">Math</span>.min(min,helper(start+i,<span class=\\"hljs-built_in\\">Math</span>.max(i,M)))\\n    }\\n    <span class=\\"hljs-keyword\\">let</span> res=rest[start]-min\\n    hash[start+<span class=\\"hljs-string\\">\' \'</span>+M]=res\\n    <span class=\\"hljs-keyword\\">return</span> res\\n  }\\n};\\n</code></pre>\\n"],"titleSlug":"stone-game-ii","hasThinking":false,"content":"<p>\u4e9a\u5386\u514b\u65af\u548c\u674e\u7ee7\u7eed\u4ed6\u4eec\u7684\u77f3\u5b50\u6e38\u620f\u3002\u8bb8\u591a\u5806\u77f3\u5b50&nbsp;<strong>\u6392\u6210\u4e00\u884c</strong>\uff0c\u6bcf\u5806\u90fd\u6709\u6b63\u6574\u6570\u9897\u77f3\u5b50&nbsp;<code>piles[i]</code>\u3002\u6e38\u620f\u4ee5\u8c01\u624b\u4e2d\u7684\u77f3\u5b50\u6700\u591a\u6765\u51b3\u51fa\u80dc\u8d1f\u3002</p>\\n\\n<p>\u4e9a\u5386\u514b\u65af\u548c\u674e\u8f6e\u6d41\u8fdb\u884c\uff0c\u4e9a\u5386\u514b\u65af\u5148\u5f00\u59cb\u3002\u6700\u521d\uff0c<code>M = 1</code>\u3002</p>\\n\\n<p>\u5728\u6bcf\u4e2a\u73a9\u5bb6\u7684\u56de\u5408\u4e2d\uff0c\u8be5\u73a9\u5bb6\u53ef\u4ee5\u62ff\u8d70\u5269\u4e0b\u7684&nbsp;<strong>\u524d</strong>&nbsp;<code>X</code>&nbsp;\u5806\u7684\u6240\u6709\u77f3\u5b50\uff0c\u5176\u4e2d&nbsp;<code>1 &lt;= X &lt;= 2M</code>\u3002\u7136\u540e\uff0c\u4ee4&nbsp;<code>M = max(M, X)</code>\u3002</p>\\n\\n<p>\u6e38\u620f\u4e00\u76f4\u6301\u7eed\u5230\u6240\u6709\u77f3\u5b50\u90fd\u88ab\u62ff\u8d70\u3002</p>\\n\\n<p>\u5047\u8bbe\u4e9a\u5386\u514b\u65af\u548c\u674e\u90fd\u53d1\u6325\u51fa\u6700\u4f73\u6c34\u5e73\uff0c\u8fd4\u56de\u4e9a\u5386\u514b\u65af\u53ef\u4ee5\u5f97\u5230\u7684\u6700\u5927\u6570\u91cf\u7684\u77f3\u5934\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>piles = [2,7,9,4,4]\\n<strong>\u8f93\u51fa\uff1a</strong>10\\n<strong>\u89e3\u91ca\uff1a\\n</strong>\u5982\u679c\u4e9a\u5386\u514b\u65af\u5728\u5f00\u59cb\u65f6\u62ff\u8d70\u4e00\u5806\u77f3\u5b50\uff0c\u674e\u62ff\u8d70\u4e24\u5806\uff0c\u63a5\u7740\u4e9a\u5386\u514b\u65af\u4e5f\u62ff\u8d70\u4e24\u5806\u3002\u5728\u8fd9\u79cd\u60c5\u51b5\u4e0b\uff0c\u4e9a\u5386\u514b\u65af\u53ef\u4ee5\u62ff\u5230 2 + 4 + 4 = 10 \u9897\u77f3\u5b50\u3002 \\n\u5982\u679c\u4e9a\u5386\u514b\u65af\u5728\u5f00\u59cb\u65f6\u62ff\u8d70\u4e24\u5806\u77f3\u5b50\uff0c\u90a3\u4e48\u674e\u5c31\u53ef\u4ee5\u62ff\u8d70\u5269\u4e0b\u5168\u90e8\u4e09\u5806\u77f3\u5b50\u3002\u5728\u8fd9\u79cd\u60c5\u51b5\u4e0b\uff0c\u4e9a\u5386\u514b\u65af\u53ef\u4ee5\u62ff\u5230 2 + 7 = 9 \u9897\u77f3\u5b50\u3002\\n\u6240\u4ee5\u6211\u4eec\u8fd4\u56de\u66f4\u5927\u7684 10\u3002 \\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>1 &lt;= piles.length &lt;= 100</code></li>\\n\\t<li><code>1 &lt;= piles[i]&nbsp;&lt;= 10 ^ 4</code></li>\\n</ul>\\n","title":"1140. \u77f3\u5b50\u6e38\u620f II","relatedTags":["\u52a8\u6001\u89c4\u5212"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1140"}')}}]);